package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    @Test
    public void testEquals_SameObject() {
        CSVFormat format = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);

        assertTrue(format.equals(format));
    }

    @Test
    public void testEquals_NullObject() {
        CSVFormat format = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);

        assertFalse(format.equals(null));
    }

    @Test
    public void testEquals_DifferentClass() {
        CSVFormat format = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);
        Object obj = new Object();

        assertFalse(format.equals(obj));
    }

    @Test
    public void testEquals_EqualObjects() {
        CSVFormat format1 = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);
        CSVFormat format2 = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);

        assertTrue(format1.equals(format2));
    }

    @Test
    public void testEquals_NotEqual_Delimiter() {
        CSVFormat format1 = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);
        CSVFormat format2 = new CSVFormat('|', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "NULL", new String[]{"Header"}, true, true);

        assertFalse(format1.equals(format2));
    }

    // Add more test cases for other fields comparison

}
